/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Responsibilities:
 * 1. Message formatting — converts NotificationPayload to SMS-friendly text
 * 2. Phone number resolution — resolves recipient to a phone number
 * 3. Delivery — sends SMS (pluggable transport, defaults to in-memory for dev/test)
 *
 * Implements NotificationAdapter interface. Must not throw — returns failed
 * NotificationResult on errors.
 *
 * NOTE: User notification preferences (src/models/user-preferences.ts) were designed
 * with email-only in mind. They need to be extended to support per-channel preferences
 * (SMS opt-in/opt-out, SMS frequency, etc.) before SMS is fully production-ready.
 * See the preferences model for details on what needs to change.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the SMS adapter.
 */
export interface SmsConfig {
  /** Sender phone number or short code */
  fromNumber: string;
  /** Maximum message length (SMS standard is 160 chars) */
  maxLength?: number;
}

export const defaultSmsConfig: SmsConfig = {
  fromNumber: '+1-555-TASKFLOW',
  maxLength: 160,
};

/**
 * A formatted SMS message ready for delivery.
 */
export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

/**
 * Transport interface for pluggable SMS delivery.
 * Implement this to swap in a real SMS provider (Twilio, AWS SNS, etc.).
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ messageId: string }>;
}

/**
 * In-memory transport for development and testing.
 * Stores all sent messages for inspection.
 */
export class InMemorySmsTransport implements SmsTransport {
  private messages: Array<SmsMessage & { messageId: string }> = [];

  async sendSms(message: SmsMessage): Promise<{ messageId: string }> {
    const messageId = `sms-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    this.messages.push({ ...message, messageId });
    return { messageId };
  }

  getMessages(): Array<SmsMessage & { messageId: string }> {
    return [...this.messages];
  }

  clear(): void {
    this.messages = [];
  }
}

/**
 * Resolve the recipient to a phone number.
 * Accepts strings that look like phone numbers (start with + or contain only digits/dashes/spaces/parens).
 * Returns undefined if the recipient doesn't look like a phone number.
 */
export type PhoneResolver = (recipient: string) => string | undefined;

function defaultPhoneResolver(recipient: string): string | undefined {
  // Accept strings starting with + (international format) or purely numeric/dash/space/paren strings
  if (recipient.startsWith('+')) {
    return recipient;
  }
  if (/^[\d\s\-()]+$/.test(recipient) && recipient.replace(/\D/g, '').length >= 7) {
    return recipient;
  }
  return undefined;
}

/**
 * Format a notification payload into an SMS-friendly text message.
 * Truncates to maxLength if specified.
 */
function formatSmsBody(payload: NotificationPayload, maxLength?: number): string {
  const text = `${payload.subject}: ${payload.body}`;
  if (maxLength && text.length > maxLength) {
    return text.slice(0, maxLength - 3) + '...';
  }
  return text;
}

export class SmsNotificationAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;
  private phoneResolver: PhoneResolver;
  private config: SmsConfig;

  constructor(options?: {
    config?: SmsConfig;
    transport?: SmsTransport;
    phoneResolver?: PhoneResolver;
  }) {
    this.config = options?.config ?? defaultSmsConfig;
    this.transport = options?.transport ?? new InMemorySmsTransport();
    this.phoneResolver = options?.phoneResolver ?? defaultPhoneResolver;
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Step 1: Resolve phone number
      const phoneNumber = this.phoneResolver(payload.recipient);
      if (!phoneNumber) {
        this.logger.warn(`Cannot resolve phone number for recipient: ${payload.recipient}`);
        return {
          notificationId: payload.id,
          channel: 'sms',
          success: false,
          error: `Cannot resolve phone number for recipient: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      // Step 2: Format message
      const smsMessage: SmsMessage = {
        to: phoneNumber,
        from: this.config.fromNumber,
        body: formatSmsBody(payload, this.config.maxLength),
      };

      // Step 3: Send via transport
      this.logger.info(`Sending SMS to ${phoneNumber} for notification ${payload.id}`);
      const result = await this.transport.sendSms(smsMessage);
      this.logger.info(`SMS delivered: ${payload.id} (messageId: ${result.messageId})`);

      return {
        notificationId: payload.id,
        channel: 'sms',
        success: true,
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send SMS for ${payload.id}: ${message}`);
      return {
        notificationId: payload.id,
        channel: 'sms',
        success: false,
        error: `SMS delivery failed: ${message}`,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get the underlying transport (for testing).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsNotificationAdapter,
  InMemorySmsTransport,
  defaultSmsConfig,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  SmsMessage,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'sms',
    recipient: '+1-555-123-4567',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    priority: 'normal',
    createdAt: new Date('2026-01-01'),
    ...overrides,
  };
}

describe('SmsNotificationAdapter', () => {
  let transport: InMemorySmsTransport;
  let adapter: SmsNotificationAdapter;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsNotificationAdapter({ transport });
  });

  it('has channel "sms"', () => {
    expect(adapter.channel).toBe('sms');
  });

  describe('send', () => {
    it('sends SMS successfully for a phone number recipient', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.notificationId).toBe('notif-0001');
      expect(result.deliveredAt).toBeInstanceOf(Date);
    });

    it('delivers SMS via transport with formatted body', async () => {
      await adapter.send(makePayload());

      const messages = transport.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]!.to).toBe('+1-555-123-4567');
      expect(messages[0]!.from).toBe(defaultSmsConfig.fromNumber);
      expect(messages[0]!.body).toContain('Order Confirmation');
      expect(messages[0]!.body).toContain('Your order has been placed.');
    });

    it('formats body as "subject: body"', async () => {
      await adapter.send(makePayload({
        subject: 'Test Subject',
        body: 'Test body text',
      }));

      const messages = transport.getMessages();
      expect(messages[0]!.body).toBe('Test Subject: Test body text');
    });

    it('truncates long messages to maxLength', async () => {
      const adapterWithShortMax = new SmsNotificationAdapter({
        transport,
        config: { fromNumber: '+1-555-0000', maxLength: 30 },
      });

      await adapterWithShortMax.send(makePayload({
        subject: 'Long Subject Here',
        body: 'This is a very long body that exceeds the max length limit',
      }));

      const messages = transport.getMessages();
      expect(messages[0]!.body.length).toBe(30);
      expect(messages[0]!.body).toMatch(/\.\.\.$/);
    });

    it('returns failure when recipient is not a phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user@example.com' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve phone number');
      expect(transport.getMessages()).toHaveLength(0);
    });

    it('returns failure when recipient is too short to be a phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: '123' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve phone number');
    });

    it('accepts numeric-only phone numbers', async () => {
      const result = await adapter.send(makePayload({ recipient: '5551234567' }));

      expect(result.success).toBe(true);
      expect(transport.getMessages()[0]!.to).toBe('5551234567');
    });

    it('accepts phone numbers with parentheses and dashes', async () => {
      const result = await adapter.send(makePayload({ recipient: '(555) 123-4567' }));

      expect(result.success).toBe(true);
      expect(transport.getMessages()[0]!.to).toBe('(555) 123-4567');
    });

    it('returns failure when transport throws', async () => {
      const failingTransport: SmsTransport = {
        sendSms: async () => {
          throw new Error('Network error');
        },
      };
      const adapterWithFailing = new SmsNotificationAdapter({
        transport: failingTransport,
      });

      const result = await adapterWithFailing.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Network error');
    });

    it('never throws, even on unexpected errors', async () => {
      const failingTransport: SmsTransport = {
        sendSms: async () => {
          throw 'string error';
        },
      };
      const adapterWithFailing = new SmsNotificationAdapter({
        transport: failingTransport,
      });

      const result = await adapterWithFailing.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toContain('string error');
    });
  });

  describe('custom phone resolver', () => {
    it('uses custom resolver when provided', async () => {
      const adapterWithResolver = new SmsNotificationAdapter({
        transport,
        phoneResolver: (recipient) => {
          if (recipient === 'user-123') return '+1-999-000-0000';
          return undefined;
        },
      });

      const result = await adapterWithResolver.send(makePayload({ recipient: 'user-123' }));

      expect(result.success).toBe(true);
      expect(transport.getMessages()[0]!.to).toBe('+1-999-000-0000');
    });

    it('returns failure when custom resolver returns undefined', async () => {
      const adapterWithResolver = new SmsNotificationAdapter({
        transport,
        phoneResolver: () => undefined,
      });

      const result = await adapterWithResolver.send(makePayload());
      expect(result.success).toBe(false);
    });
  });

  describe('custom config', () => {
    it('uses custom fromNumber', async () => {
      const adapterWithConfig = new SmsNotificationAdapter({
        transport,
        config: { fromNumber: '+44-700-000-0000' },
      });

      await adapterWithConfig.send(makePayload());
      expect(transport.getMessages()[0]!.from).toBe('+44-700-000-0000');
    });
  });

  describe('InMemorySmsTransport', () => {
    it('stores sent messages', async () => {
      const t = new InMemorySmsTransport();
      const message: SmsMessage = {
        to: '+1-555-000-0000',
        from: '+1-555-999-9999',
        body: 'Test message',
      };

      const result = await t.sendSms(message);

      expect(result.messageId).toMatch(/^sms-/);
      expect(t.getMessages()).toHaveLength(1);
      expect(t.getMessages()[0]!.to).toBe('+1-555-000-0000');
    });

    it('clears messages', async () => {
      const t = new InMemorySmsTransport();
      await t.sendSms({ to: '+1-555-000-0000', from: '+1-555-999-9999', body: 'Test' });

      t.clear();
      expect(t.getMessages()).toHaveLength(0);
    });
  });

  describe('defaults', () => {
    it('has default fromNumber config', () => {
      expect(defaultSmsConfig.fromNumber).toBe('+1-555-TASKFLOW');
    });

    it('has default maxLength of 160', () => {
      expect(defaultSmsConfig.maxLength).toBe(160);
    });
  });
});

